                    <button onClick={() => setActiveTab('proposals')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'proposals' ? 'border-secondary-accent text-secondary-accent bg-white dark:bg-slate-800' : 'border-transparent text-slate-500 hover:text-slate-800'}`}>Proposals & Files</button>
                    <button onClick={() => setActiveTab('tasks')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'tasks' ? 'border-secondary-accent text-secondary-accent bg-white dark:bg-slate-800' : 'border-transparent text-slate-500 hover:text-slate-800'}`}>Tasks</button>
