                                            <p className="text-sm text-slate-800 dark:text-slate-300">{log.note}</p>
                                        </div>
                                    </div>
                                )) : (
                                    <p className="text-sm text-slate-400 italic pl-6">No history yet.</p>
                                )}
                                {/* Creation Event */}
