                                    <div className="absolute -left-[23px] top-1 w-3 h-3 rounded-full bg-green-500 border-2 border-white dark:border-slate-800"></div>
                                    <p className="text-xs text-slate-500">Lead created on {safeFormatDate(lead.dateAdded)}</p>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* TAB 2: THE AUDIT (QUALIFICATION) */}
                    {activeTab === 'audit' && (
                        <div className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <Card title="Qualification Data" className="bg-white dark:bg-slate-800">
                                    <dl className="space-y-4 text-sm">
                                        <div><dt className="text-slate-500 text-xs uppercase">Est. Revenue</dt><dd className="font-bold text-slate-800 dark:text-slate-100">{lead.revenueBand || '-'}</dd></div>
                                        <div><dt className="text-slate-500 text-xs uppercase">Ad Status</dt><dd className="font-bold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                                            {lead.adStatus === 'Active' ? <CheckCircle2 className="w-4 h-4 text-green-500"/> : <XCircle className="w-4 h-4 text-slate-400"/>}
                                            {lead.adStatus || 'Unknown'}
                                        </dd></div>
                                        <div><dt className="text-slate-500 text-xs uppercase">Tech Stack</dt><dd className="font-medium text-slate-800 dark:text-slate-100">{Array.isArray(lead.techStack) ? lead.techStack.join(', ') : lead.techStack || '-'}</dd></div>
                                        <div><dt className="text-slate-500 text-xs uppercase">Niche / Vertical</dt><dd className="font-medium text-slate-800 dark:text-slate-100">{Array.isArray(lead.tags) ? lead.tags.join(', ') : '-'}</dd></div>
                                    </dl>
                                </Card>

                                <Card title="The Hook & Outreach" className="bg-white dark:bg-slate-800">
                                    <div className="space-y-4">
                                        <div className="p-3 bg-amber-50 dark:bg-amber-900/10 rounded-lg border border-amber-100 dark:border-amber-800/30">
                                            <p className="text-xs font-bold text-amber-800 uppercase mb-1">Outreach Angle (Problem Spot)</p>
                                            <p className="text-sm text-amber-900 dark:text-amber-100 italic">"{lead.outreachAngle || 'No specific angle recorded.'}"</p>
                                        </div>
                                        <div className="p-3 bg-blue-50 dark:bg-blue-900/10 rounded-lg border border-blue-100 dark:border-blue-800/30">
                                            <p className="text-xs font-bold text-blue-800 uppercase mb-1">Offer Sent (Free Value)</p>
                                            <p className="text-sm text-blue-900 dark:text-blue-100">{lead.offerSent || 'None sent yet.'}</p>
                                        </div>
                                    </div>
                                </Card>
                            </div>

                            <Card title="Audit Report" className="bg-white dark:bg-slate-800" 
                                actions={!relatedAudit && <Button size="sm" onClick={() => onOpenAuditFormModal(lead)}>Create Audit</Button>}
                            >
                                {relatedAudit ? (
                                    <div className="flex items-center justify-between p-3 border rounded-lg hover:shadow-sm transition-shadow cursor-pointer" onClick={() => onOpenAuditReportModal(lead, relatedAudit)}>
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 bg-purple-100 dark:bg-purple-900/30 text-purple-600 rounded-lg"><FileScan className="w-5 h-5"/></div>
                                            <div>
                                                <p className="font-bold text-slate-800 dark:text-white">Growth Audit Report</p>
                                                <p className="text-xs text-slate-500">Score: {relatedAudit.aiOverallScore}/100 • {safeFormatDate(relatedAudit.dateConducted)}</p>
                                            </div>
                                        </div>
                                        <Button variant="ghost" size="sm">View PDF</Button>
                                    </div>
                                ) : (
                                    <p className="text-sm text-slate-400 text-center py-4">No audit generated yet.</p>
                                )}
                            </Card>
                        </div>
                    )}

                    {/* TAB 3: PROPOSALS & FILES */}
                    {activeTab === 'proposals' && (
                        <div className="space-y-4">
                            <div className="flex justify-between items-center mb-2">
                                <h3 className="font-bold text-slate-700 dark:text-white">Proposals</h3>
                                <Button size="sm" onClick={() => openModal('PROPOSAL_FORM', { proposal: { clientId: lead.id } })} leftIcon={<Plus className="w-4 h-4"/>}>New Proposal</Button>
                            </div>

                            {relatedProposals.length > 0 ? (
                                <div className="space-y-3">
                                    {relatedProposals.map(prop => (
                                        <div key={prop.id} onClick={() => onOpenProposalPanel(prop)} className="flex items-center justify-between p-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg hover:border-premium-accent cursor-pointer transition-colors group">
                                            <div className="flex items-center gap-3">
                                                <div className="p-2 bg-slate-100 dark:bg-slate-700 rounded-lg text-slate-500 group-hover:text-premium-accent transition-colors">
                                                    <FileText className="w-5 h-5" />
                                                </div>
                                                <div>
                                                    <h4 className="font-semibold text-sm text-text-heading dark:text-slate-100">{prop.title || `Proposal #${prop.proposalNumber}`}</h4>
                                                    <p className="text-xs text-text-muted">Version {prop.version} • Created {safeFormatDate(prop.generatedDate)}</p>
                                                </div>
                                            </div>
                                            <span className={`px-2.5 py-1 rounded-full text-xs font-medium bg-slate-100 text-slate-600 dark:bg-slate-700 dark:text-slate-300`}>
                                                {prop.status}
                                            </span>
                                        </div>
                                    ))}
                                </div>
                            ) : <p className="text-sm text-slate-400 italic">No proposals created.</p>}

                            <div className="border-t border-slate-200 dark:border-slate-700 my-6"></div>

                            <div className="flex justify-between items-center mb-2">
                                <h3 className="font-bold text-slate-700 dark:text-white">Files</h3>
                                <Button size="sm" variant="outline" onClick={() => alert('Upload placeholder')}>Upload File</Button>
                            </div>
                             <p className="text-sm text-slate-400 italic">No files uploaded.</p>
                        </div>
                    )}

                    {/* TAB 4: TASKS */}
                    {activeTab === 'tasks' && (
                         <div className="space-y-4">
                            <div className="flex justify-between items-center mb-2">
                                <h3 className="font-bold text-slate-700 dark:text-white">Tasks</h3>
                                <Button size="sm" variant="outline" onClick={() => openModal('TASK_FORM')}>Add Task</Button>
                            </div>
                            <p className="text-sm text-slate-400 italic text-center py-8">
                                No specific tasks linked to this lead. <br/>
                                (Use the "Log Activity" button to track calls/meetings or create a general task).
                            </p>
                         </div>
                    )}

                </div>
            </div>
       </div>
    </Modal>
  );
};

