export type DiscountType = 'None' | 'Percentage' | 'Fixed';
export type RecurrenceFrequency = 'Weekly' | 'Monthly' | 'Quarterly' | 'Yearly';
export const recurrenceFrequencies: RecurrenceFrequency[] = ['Weekly', 'Monthly', 'Quarterly', 'Yearly'];

