const PIPELINE_STAGES: { status: LeadStatus; label: string; icon: React.ElementType }[] = [
  { status: 'New', label: 'New', icon: Circle },
  { status: 'Qualified', label: 'Qual.', icon: CheckCircle2 },
  { status: 'Contacted', label: 'Contact', icon: Mail },
  { status: 'Audit in Progress', label: 'Audit', icon: FileScan },
  { status: 'Pitch Scheduled', label: 'Pitch', icon: Calendar },
  { status: 'Negotiation', label: 'Nego.', icon: FileText },
  { status: 'Closed Won', label: 'Won', icon: UserCheck },
];

const getInitials = (name?: string): string => {
    if (!name) return '?';
    const parts = name.trim().split(/\s+/);
    if (parts.length === 0 || parts[0] === "") return '?';
    if (parts.length === 1) return parts[0][0]?.toUpperCase() || '?';
    return (parts[0][0]?.toUpperCase() || '') + (parts[parts.length - 1][0]?.toUpperCase() || '');
};

const LeadDetailView: React.FC<LeadDetailViewProps> = ({ 
    isOpen, onClose, lead, auditRecords, proposals, teamMembers, onEditLead, 
    hasPermission, onUpdateStatus, onOpenFollowUpModal, onOpenAuditFormModal, 
    onOpenAuditReportModal, onOpenProjectsDrawer, clients, openModal, onOpenProposalPanel
}) => {

  const [activeTab, setActiveTab] = useState<'timeline' | 'audit' | 'proposals' | 'tasks'>('timeline');

  const clientRecordForLead = useMemo(() => {
    if (lead.status === 'Closed Won') { // Changed to Closed Won as standard converted status
        return clients.find(c => c.convertedFromLeadId === lead.id || c.email === lead.email);
    }
    return null;
  }, [clients, lead]);

  const relatedAudit = useMemo(() => auditRecords.find(a => a.leadId === lead.id), [auditRecords, lead.id]);
  const relatedProposals = useMemo(() => proposals.filter(p => p.clientId === lead.id), [proposals, lead.id]);
  const leadOwner = useMemo(() => teamMembers.find(t => t.id === lead.assignedToUserId), [teamMembers, lead.assignedToUserId]);

  const handleStatusChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
      onUpdateStatus(lead.id, e.target.value as LeadStatus);
  };

  const handlePipelineClick = (status: LeadStatus) => {
    if (hasPermission('leads', 'canUpdateStatus')) {
        onUpdateStatus(lead.id, status);
    }
  };

  if (!isOpen) return null;

  // Determine active stage index for progress bar
  const currentStageIndex = PIPELINE_STAGES.findIndex(s => s.status === lead.status);
  const activeStageIndex = currentStageIndex === -1 ? 0 : currentStageIndex;

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={
        <div className="flex items-center justify-between w-full pr-8">
            <div className="flex items-center gap-3">
                 <div className="w-10 h-10 rounded-full bg-slate-200 dark:bg-slate-700 flex items-center justify-center font-bold text-premium-accent text-lg">
                    {getInitials(lead.name)}
                </div>
                <div>
                    <h2 className="text-xl font-bold text-text-heading dark:text-text-heading">{lead.name}</h2>
                    <div className="flex items-center gap-2 text-sm text-text-muted">
                        {lead.companyName && <span className="font-medium text-slate-700 dark:text-slate-300">{lead.companyName}</span>}
                        {lead.instagramHandle && (
                            <a href={`https://instagram.com/${lead.instagramHandle.replace('@', '')}`} target="_blank" rel="noopener noreferrer" className="text-pink-600 hover:underline flex items-center gap-1">
                                <Instagram className="w-3 h-3"/> {lead.instagramHandle}
                            </a>
                        )}
                        {lead.website && (
                             <a href={lead.website.startsWith('http') ? lead.website : `https://${lead.website}`} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline flex items-center gap-1">
                                <Globe className="w-3 h-3"/> Website
                            </a>
                        )}
                    </div>
                </div>
            </div>

            <div className="flex items-center gap-3">
                 <select 
                    value={lead.status} 
                    onChange={handleStatusChange}
                    className="px-3 py-1.5 bg-white dark:bg-slate-700 border border-slate-300 dark:border-slate-600 rounded-lg text-sm font-medium focus:ring-2 focus:ring-premium-accent outline-none cursor-pointer"
                 >
                    {['New', 'Qualified', 'Contacted', 'Engaged', 'Audit in Progress', 'Pitch Scheduled', 'Negotiation', 'Closed Won', 'Closed Lost'].map(s => (
                        <option key={s} value={s}>{s}</option>
                    ))}
                 </select>

                 <Button variant="outline" size="sm" onClick={() => onOpenFollowUpModal(lead)} leftIcon={<Clock className="w-4 h-4"/>}>
                    Log Activity
                 </Button>

                 {lead.status !== 'Closed Won' && (
                    <Button variant="primary" size="sm" onClick={() => onUpdateStatus(lead.id, 'Closed Won')} leftIcon={<UserCheck className="w-4 h-4"/>}>
                        Convert to Client
                    </Button>
                 )}
            </div>
        </div>
    } size="7xl">

       {/* Pipeline Visual */}
        <div className="w-full bg-slate-50 dark:bg-slate-800/50 p-4 mb-6 rounded-xl border border-border-base dark:border-slate-700 overflow-x-auto">
            <div className="flex items-center justify-between relative min-w-[600px]">
                    {/* Progress Line Background */}
                <div className="absolute top-4 left-0 w-full h-1 bg-slate-200 dark:bg-slate-700 -z-0 rounded-full" />
                {/* Active Progress Line */}
