                    className="absolute top-4 left-0 h-1 bg-secondary-accent -z-0 rounded-full transition-all duration-500 ease-in-out" 
                    style={{ width: `${(activeStageIndex / (PIPELINE_STAGES.length - 1)) * 100}%` }} 
                />

                {PIPELINE_STAGES.map((stage, index) => {
                    const isCompleted = index <= activeStageIndex;
                    const isCurrent = index === activeStageIndex;
                    const Icon = stage.icon;

                    return (
                        <div key={stage.status} className="flex flex-col items-center relative z-10 group cursor-pointer" onClick={() => handlePipelineClick(stage.status)}>
                            <div
