            contactId,
            senderId: 'me',
            text,
            timestamp: new Date().toISOString(),
            status: 'sent'
        };
        setChatMessages(prev => [...prev, newMessage]);
        setChatContacts(prev => prev.map(c => c.id === contactId ? { ...c, lastMessage: text, lastMessageTimestamp: newMessage.timestamp } : c));
    };

