        const newEmail: EmailMessage = {
            ...emailData,
            id: emailData.id || `email-${Date.now()}`,
            senderName: currentUser?.name || 'Unknown',
            timestamp: new Date().toISOString(),
            folder: action === 'send' ? 'sent' : 'drafts',
            isRead: true
        } as EmailMessage;
        setEmails(prev => [newEmail, ...prev]);
        return true;
    };

