const getInitials = (name?: string): string => {
    if (!name) return '?';
    const parts = name.trim().split(/\s+/);
    if (parts.length === 0 || parts[0] === "") return '?';
    if (parts.length === 1) return parts[0][0]?.toUpperCase() || '?';
    return (parts[0][0]?.toUpperCase() || '') + (parts[parts.length - 1][0]?.toUpperCase() || '');
};

// --- LEAD QUALIFICATION LOGIC ---
const calculateLeadFit = (lead: Lead): { label: 'Low Fit' | 'Medium Fit' | 'High Fit'; color: string; score: number } => {
    let score = 0;

    // Revenue Scoring
    if (lead.revenueBand === "$10k - $50k/mo") score += 1;
    else if (lead.revenueBand === "$50k - $100k/mo") score += 3;
    else if (lead.revenueBand === "$100k+/mo") score += 3;

    // Ad Status Scoring
    if (lead.adStatus === 'Active') score += 2;

    // Classification
    if (score >= 3) return { label: 'High Fit', color: 'bg-green-100 text-green-700 border-green-200', score };
    if (score >= 1) return { label: 'Medium Fit', color: 'bg-yellow-100 text-yellow-700 border-yellow-200', score };
    return { label: 'Low Fit', color: 'bg-red-100 text-red-700 border-red-200', score };
};

