const PIPELINE_STAGES: { status: LeadStatus; label: string; icon: React.ElementType }[] = [
  { status: 'New', label: 'New', icon: Circle },
  { status: 'Qualified', label: 'Qual.', icon: CheckCircle2 },
  { status: 'Contacted', label: 'Contact', icon: Mail },
  { status: 'Audit in Progress', label: 'Audit', icon: FileScan },
  { status: 'Pitch Scheduled', label: 'Pitch', icon: Calendar },
  { status: 'Negotiation', label: 'Nego.', icon: FileText },
  { status: 'Closed Won', label: 'Won', icon: UserCheck },
];

const getInitials = (name?: string): string => {
    if (!name) return '?';
    const parts = name.trim().split(/\s+/);
    if (parts.length === 0 || parts[0] === "") return '?';
    if (parts.length === 1) return parts[0][0]?.toUpperCase() || '?';
    return (parts[0][0]?.toUpperCase() || '') + (parts[parts.length - 1][0]?.toUpperCase() || '');
};

