                        <div className="flex items-center gap-2">
                             <Phone className="w-4 h-4 text-slate-400"/>
                             <span>{lead.phone || 'N/A'}</span>
                        </div>
                         <div className="flex items-center gap-2">
                             <Map className="w-4 h-4 text-slate-400"/>
                             <span className="text-slate-600 dark:text-slate-300">Remote / Unknown</span>
                        </div>
                    </div>
                </Card>

                {/* Business Profile Card */}
                <Card title="Business Profile" className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700">
                     <div className="space-y-3">
                         <div>
                             <p className="text-xs font-semibold text-slate-500 uppercase">Industry / Niche</p>
                             <p className="text-sm font-medium">{Array.isArray(lead.tags) ? lead.tags.join(', ') : 'Unspecified'}</p>
                         </div>
                         <div>
                             <p className="text-xs font-semibold text-slate-500 uppercase">Monthly Revenue</p>
                             <p className="text-sm font-bold text-green-600 dark:text-green-400">{lead.revenueBand || 'Unknown'}</p>
                         </div>
                          <div>
                             <p className="text-xs font-semibold text-slate-500 uppercase">Est. Budget</p>
                             <p className="text-sm text-slate-600 dark:text-slate-300">{lead.estimatedBudget || 'N/A'}</p>
                         </div>
                         {/* Visual indication if Qualification is complete */}
                         <div className="pt-2 border-t border-slate-100 dark:border-slate-700">
                             <p className="text-xs font-semibold text-slate-500 uppercase">Qualification Status</p>
                             {lead.qualificationCompleted ? (
                                <span className="flex items-center gap-1 text-green-600 text-sm font-medium"><CheckCircle2 className="w-4 h-4"/> Complete</span>
                             ) : (
                                 <span className="flex items-center gap-1 text-amber-600 text-sm font-medium"><AlertCircle className="w-4 h-4"/> Missing Data</span>
                             )}
                         </div>
                     </div>
                </Card>

                {/* Internal Info Card */}
                <Card title="Internal Info" className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700"
                    actions={<Button variant="ghost" size="xs" onClick={() => onEditLead(lead)}><Edit className="w-3 h-3"/></Button>}
                >
                     <div className="space-y-3">
                         <div className="flex justify-between items-center">
                             <p className="text-sm text-slate-500">Lead Owner</p>
                             <div className="flex items-center gap-2">
                                 {leadOwner ? (
                                     <>
                                        <div className="w-5 h-5 rounded-full bg-slate-200 flex items-center justify-center text-[10px] font-bold">{getInitials(leadOwner.name)}</div>
                                        <span className="text-sm">{leadOwner.name}</span>
                                     </>
                                 ) : <span className="text-sm italic text-slate-400">Unassigned</span>}
                             </div>
                         </div>
                         <div className="flex justify-between items-center">
                             <p className="text-sm text-slate-500">Source</p>
                             <span className="px-2 py-0.5 bg-slate-100 dark:bg-slate-700 rounded text-xs">{lead.source || 'Unknown'}</span>
                         </div>
                          <div>
                             <p className="text-xs font-semibold text-slate-500 uppercase mb-1">Tags</p>
                             <div className="flex flex-wrap gap-1">
                                {lead.tags && lead.tags.length > 0 ? lead.tags.map(t => <span key={t} className="text-xs px-1.5 py-0.5 bg-slate-100 dark:bg-slate-700 rounded text-slate-600 dark:text-slate-300">#{t}</span>) : <span className="text-xs text-slate-400">-</span>}
                             </div>
                         </div>
                     </div>
                </Card>
            </div>

            {/* RIGHT MAIN CONTENT: Dynamic Tabs (70%) */}
            <div className="flex-1 flex flex-col bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
                {/* Tabs Header */}
                <div className="flex items-center border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50">
                    <button onClick={() => setActiveTab('timeline')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'timeline' ? 'border-secondary-accent text-secondary-accent bg-white dark:bg-slate-800' : 'border-transparent text-slate-500 hover:text-slate-800'}`}>Timeline</button>
                    <button onClick={() => setActiveTab('audit')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'audit' ? 'border-secondary-accent text-secondary-accent bg-white dark:bg-slate-800' : 'border-transparent text-slate-500 hover:text-slate-800'}`}>The Audit</button>
                    <button onClick={() => setActiveTab('proposals')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'proposals' ? 'border-secondary-accent text-secondary-accent bg-white dark:bg-slate-800' : 'border-transparent text-slate-500 hover:text-slate-800'}`}>Proposals & Files</button>
                    <button onClick={() => setActiveTab('tasks')} className={`px-6 py-3 text-sm font-medium border-b-2 transition-colors ${activeTab === 'tasks' ? 'border-secondary-accent text-secondary-accent bg-white dark:bg-slate-800' : 'border-transparent text-slate-500 hover:text-slate-800'}`}>Tasks</button>
                </div>

                {/* Tab Content */}
                <div className="flex-1 overflow-y-auto p-6 bg-slate-50/30 dark:bg-slate-900/10">

                    {/* TAB 1: TIMELINE */}
                    {activeTab === 'timeline' && (
                        <div className="space-y-6">
                            {/* Input Box */}
                            <div className="bg-white dark:bg-slate-800 p-4 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm flex gap-3">
                                <div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-700 flex-shrink-0 flex items-center justify-center font-bold text-slate-500 text-xs">YOU</div>
                                <div className="flex-1">
                                    <input 
                                        type="text" 
                                        placeholder="Write a note or log a call..." 
                                        className="w-full bg-transparent border-none focus:ring-0 text-sm p-0 mb-2 placeholder-slate-400"
                                        onKeyDown={(e) => {
                                            if(e.key === 'Enter') {
                                                // Simplified: In real app, call a handler to add note
                                                onOpenFollowUpModal(lead);
                                            }
                                        }}
                                    />
                                    <div className="flex gap-2">
                                        <Button size="xs" variant="ghost" className="text-slate-500" onClick={() => onOpenFollowUpModal(lead)}><Phone className="w-3 h-3 mr-1"/> Log Call</Button>
                                        <Button size="xs" variant="ghost" className="text-slate-500" onClick={() => openModal('EMAIL_COMPOSE', { initialEmail: { recipientEmail: lead.email } })}><Mail className="w-3 h-3 mr-1"/> Send Email</Button>
                                    </div>
                                </div>
                            </div>

                            {/* Feed */}
                            <div className="space-y-6 pl-4 border-l-2 border-slate-200 dark:border-slate-700 ml-4">
                                {lead.followUpHistory && lead.followUpHistory.length > 0 ? lead.followUpHistory.map(log => (
                                    <div key={log.id} className="relative pl-6">
                                        <div className="absolute -left-[23px] top-1 w-3 h-3 rounded-full bg-slate-300 border-2 border-white dark:border-slate-800 dark:bg-slate-600"></div>
                                        <div className="bg-white dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm">
                                            <div className="flex justify-between text-xs text-slate-500 mb-1">
                                                <span className="font-semibold text-slate-700 dark:text-slate-200">{log.followUpType} by {log.addedByUserName}</span>
                                                <span>{safeFormatRelativeTime(log.timestamp)}</span>
                                            </div>
                                            <p className="text-sm text-slate-800 dark:text-slate-300">{log.note}</p>
                                        </div>
                                    </div>
                                )) : (
                                    <p className="text-sm text-slate-400 italic pl-6">No history yet.</p>
                                )}
                                {/* Creation Event */}
                                <div className="relative pl-6">
                                    <div className="absolute -left-[23px] top-1 w-3 h-3 rounded-full bg-green-500 border-2 border-white dark:border-slate-800"></div>
                                    <p className="text-xs text-slate-500">Lead created on {safeFormatDate(lead.dateAdded)}</p>
                                </div>
                            </div>
                        </div>
                    )}

                    {/* TAB 2: THE AUDIT (QUALIFICATION) */}
                    {activeTab === 'audit' && (
                        <div className="space-y-6">
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <Card title="Qualification Data" className="bg-white dark:bg-slate-800">
                                    <dl className="space-y-4 text-sm">
                                        <div><dt className="text-slate-500 text-xs uppercase">Est. Revenue</dt><dd className="font-bold text-slate-800 dark:text-slate-100">{lead.revenueBand || '-'}</dd></div>
                                        <div><dt className="text-slate-500 text-xs uppercase">Ad Status</dt><dd className="font-bold text-slate-800 dark:text-slate-100 flex items-center gap-2">
                                            {lead.adStatus === 'Active' ? <CheckCircle2 className="w-4 h-4 text-green-500"/> : <XCircle className="w-4 h-4 text-slate-400"/>}
                                            {lead.adStatus || 'Unknown'}
                                        </dd></div>
                                        <div><dt className="text-slate-500 text-xs uppercase">Tech Stack</dt><dd className="font-medium text-slate-800 dark:text-slate-100">{Array.isArray(lead.techStack) ? lead.techStack.join(', ') : lead.techStack || '-'}</dd></div>
                                        <div><dt className="text-slate-500 text-xs uppercase">Niche / Vertical</dt><dd className="font-medium text-slate-800 dark:text-slate-100">{Array.isArray(lead.tags) ? lead.tags.join(', ') : '-'}</dd></div>
                                    </dl>
                                </Card>

                                <Card title="The Hook & Outreach" className="bg-white dark:bg-slate-800">
                                    <div className="space-y-4">
                                        <div className="p-3 bg-amber-50 dark:bg-amber-900/10 rounded-lg border border-amber-100 dark:border-amber-800/30">
                                            <p className="text-xs font-bold text-amber-800 uppercase mb-1">Outreach Angle (Problem Spot)</p>
                                            <p className="text-sm text-amber-900 dark:text-amber-100 italic">"{lead.outreachAngle || 'No specific angle recorded.'}"</p>
                                        </div>
                                        <div className="p-3 bg-blue-50 dark:bg-blue-900/10 rounded-lg border border-blue-100 dark:border-blue-800/30">
                                            <p className="text-xs font-bold text-blue-800 uppercase mb-1">Offer Sent (Free Value)</p>
                                            <p className="text-sm text-blue-900 dark:text-blue-100">{lead.offerSent || 'None sent yet.'}</p>
                                        </div>
                                    </div>
                                </Card>
                            </div>

                            <Card title="Audit Report" className="bg-white dark:bg-slate-800" 
                                actions={
                                    !relatedAudit && (
                                        lead.leadFit === 'Low Fit' ? (
                                            <span className="text-xs text-red-500 font-bold flex items-center gap-1 border border-red-200 bg-red-50 px-2 py-1 rounded">
                                                <ShieldAlert className="w-4 h-4"/> Audit Blocked
                                            </span>
                                        ) : (
                                            <Button size="sm" onClick={() => onOpenAuditFormModal(lead)}>
                                                {lead.leadFit === 'Medium Fit' ? 'Create Audit Preview' : 'Create Full Audit'}
                                            </Button>
                                        )
                                    )
                                }
                            >
                                {relatedAudit ? (
                                    <div className="flex items-center justify-between p-3 border rounded-lg hover:shadow-sm transition-shadow cursor-pointer" onClick={() => onOpenAuditReportModal(lead, relatedAudit)}>
                                        <div className="flex items-center gap-3">
                                            <div className="p-2 bg-purple-100 dark:bg-purple-900/30 text-purple-600 rounded-lg"><FileScan className="w-5 h-5"/></div>
                                            <div>
                                                <p className="font-bold text-slate-800 dark:text-white">Growth Audit Report</p>
                                                <p className="text-xs text-slate-500">Score: {relatedAudit.aiOverallScore}/100 • {safeFormatDate(relatedAudit.dateConducted)}</p>
                                            </div>
                                        </div>
                                        <Button variant="ghost" size="sm">View PDF</Button>
                                    </div>
                                ) : (
                                    lead.leadFit === 'Low Fit' ? (
                                        <div className="text-center py-6 bg-red-50 dark:bg-red-900/10 rounded-lg border border-red-100 dark:border-red-900/30">
                                            <Lock className="w-8 h-8 text-red-400 mx-auto mb-2" />
                                            <p className="text-sm font-semibold text-red-800 dark:text-red-300">Qualification Failed</p>
                                            <p className="text-xs text-red-600 dark:text-red-400 mt-1">Revenue/Fit score is too low for a custom audit. Archive lead or nurture.</p>
                                        </div>
                                    ) : (
                                        <p className="text-sm text-slate-400 text-center py-4">No audit generated yet. Click "Create Audit" to start.</p>
                                    )
                                )}
                            </Card>
                        </div>
                    )}

                    {/* TAB 3: PROPOSALS & FILES */}
                    {activeTab === 'proposals' && (
                        <div className="space-y-4">
                            <div className="flex justify-between items-center mb-2">
                                <h3 className="font-bold text-slate-700 dark:text-white">Proposals</h3>
                                {/* Block Proposal creation if status is too early */}
                                {(['New', 'Qualified', 'Contacted', 'Engaged'].includes(lead.status) && lead.leadFit !== 'High Fit') ? (
                                     <span className="text-xs text-amber-600 bg-amber-50 px-2 py-1 rounded border border-amber-200 flex items-center gap-1">
                                        <Lock className="w-3 h-3"/> Complete Audit first
                                     </span>
                                ) : (
                                    <Button size="sm" onClick={() => openModal('PROPOSAL_FORM', { proposal: { clientId: lead.id } })} leftIcon={<Plus className="w-4 h-4"/>}>New Proposal</Button>
                                )}
                            </div>

                            {relatedProposals.length > 0 ? (
                                <div className="space-y-3">
                                    {relatedProposals.map(prop => (
                                        <div key={prop.id} onClick={() => onOpenProposalPanel(prop)} className="flex items-center justify-between p-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg hover:border-premium-accent cursor-pointer transition-colors group">
                                            <div className="flex items-center gap-3">
                                                <div className="p-2 bg-slate-100 dark:bg-slate-700 rounded-lg text-slate-500 group-hover:text-premium-accent transition-colors">
                                                    <FileText className="w-5 h-5" />
                                                </div>
                                                <div>
                                                    <h4 className="font-semibold text-sm text-text-heading dark:text-slate-100">{prop.title || `Proposal #${prop.proposalNumber}`}</h4>
                                                    <p className="text-xs text-text-muted">Version {prop.version} • Created {safeFormatDate(prop.generatedDate)}</p>
                                                </div>
                                            </div>
                                            <span className={`px-2.5 py-1 rounded-full text-xs font-medium bg-slate-100 text-slate-600 dark:bg-slate-700 dark:text-slate-300`}>
                                                {prop.status}
                                            </span>
                                        </div>
                                    ))}
                                </div>
                            ) : <p className="text-sm text-slate-400 italic">No proposals created.</p>}

                            <div className="border-t border-slate-200 dark:border-slate-700 my-6"></div>

                            <div className="flex justify-between items-center mb-2">
                                <h3 className="font-bold text-slate-700 dark:text-white">Files</h3>
                                <Button size="sm" variant="outline" onClick={() => alert('Upload placeholder')}>Upload File</Button>
                            </div>
                             <p className="text-sm text-slate-400 italic">No files uploaded.</p>
                        </div>
                    )}

                    {/* TAB 4: TASKS */}
                    {activeTab === 'tasks' && (
                         <div className="space-y-4">
                            <div className="flex justify-between items-center mb-2">
                                <h3 className="font-bold text-slate-700 dark:text-white">Tasks</h3>
                                <Button size="sm" variant="outline" onClick={() => openModal('TASK_FORM')}>Add Task</Button>
                            </div>
                            <p className="text-sm text-slate-400 italic text-center py-8">
                                No specific tasks linked to this lead. <br/>
                                (Use the "Log Activity" button to track calls/meetings or create a general task).
                            </p>
                         </div>
                    )}

                </div>
            </div>
       </div>
    </Modal>
  );
};

// Missing Icon Component
const XCircle: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className={className || "w-5 h-5"}><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.28 7.22a.75.75 0 00-1.06 1.06L8.94 10l-1.72 1.72a.75.75 0 101.06 1.06L10 11.06l1.72 1.72a.75.75 0 101.06-1.06L11.06 10l1.72-1.72a.75.75 0 00-1.06-1.06L10 8.94 8.28 7.22z" clipRule="evenodd" /></svg>;


export default LeadDetailView;

import React from 'react';

// --- Core Types ---
export type View = 'DASHBOARD' | 'CLIENTS' | 'INVOICES' | 'LEADS' | 'LEAD_DETAIL' | 'TEAM' | 'TEAM_MEMBER_DETAIL' | 'EXPENSES' | 'MARKETING_AUDITS' | 'AUDIT_DETAIL' | 'ADMIN_PANEL' | 'CALENDAR' | 'TIME_LOGS' | 'ONBOARDING' | 'CAMPAIGN_ANALYTICS' | 'CAMPAIGNS' | 'USER_PROFILE' | 'INTEGRATIONS' | 'COMMUNICATION' | 'LEAVES' | 'HR_MODULE' | 'FINANCE' | 'CLIENT_DETAIL' | 'PROJECT_DETAIL' | 'PROJECTS' | 'TASKS' | 'MY_TASKS' | 'SOP_LIBRARY' | 'AUDITS' | 'TOOLS';

export type FeatureKey = 'dashboard' | 'leads' | 'clients' | 'projects' | 'tasks' | 'projectTasks' | 'invoices' | 'expenses' | 'finance' | 'hrModule' | 'leaves' | 'calendar' | 'communication' | 'userProfile' | 'adminPanel' | 'adminUsers' | 'adminRoles' | 'adminSettings' | 'adminData' | 'marketingAudits' | 'leadAudit' | 'timeTracking' | 'notifications' | 'sopLibrary' | 'onboarding' | 'campaigns' | 'integrations' | 'tools' | 'adminTimeLogs' | 'auditDetail';
export type PermissionAction = 'canView' | 'canCreate' | 'canEdit' | 'canDelete' | 'canUpdateStatus' | 'canConvert' | 'canAssignTeam' | 'canMarkComplete' | 'canAssignSelf' | 'canAssignOthers' | 'canSend' | 'canManageRecurring' | 'canViewHRModule' | 'canManageHRMembers' | 'canMarkAttendance' | 'canViewOwnLeave' | 'canRequestLeave' | 'canCancelOwnLeave' | 'canViewAllLeave' | 'canManageLeaveRequests' | 'canManageDrafts' | 'canDeleteEmails' | 'canUpdateProfile' | 'canManage' | 'canConductAudit' | 'canViewAuditReport' | 'canLogTime' | 'canViewOwnTime' | 'canEditOwnTime' | 'canDeleteOwnTime' | 'canViewAllTime' | 'canManageAllTimeLogs' | 'canViewNotifications' | 'canManageProposals' | 'canManageKickoffForms' | 'canGenerateReport';

export interface AppFeaturePermission {
    featureKey: FeatureKey;
    featureName: string;
    availablePermissions: { action: PermissionAction; label: string }[];
    currentPermissions: PermissionFlags;
}

export type PermissionFlags = Partial<Record<PermissionAction, boolean>>;

export interface RoleDefinition {
    id: string;
    name: string;
    description?: string;
    permissions: AppFeaturePermission[];
    isSystemRole?: boolean;
}

export type TeamMemberRole = 'Admin' | 'Manager' | 'Strategist' | 'Designer' | 'Developer' | 'Member';

export type HRStatus = 'Active' | 'Resigned' | 'On Leave' | 'Probation' | 'Contract' | 'Terminated';
